    'REVISIT',
    'KYC'
);


--
-- Name: assign_rate_types_to_area(integer, integer[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.assign_rate_types_to_area(p_area_id integer, rate_type_ids integer[], p_user_id uuid) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    rt_id INTEGER;
    inserted_count INTEGER := 0;
BEGIN
    FOREACH rt_id IN ARRAY rate_type_ids
    LOOP
        INSERT INTO area_rate_types (area_id, rate_type_id, created_by)
        VALUES (p_area_id, rt_id, p_user_id)
        ON CONFLICT (area_id, rate_type_id) DO NOTHING;
        inserted_count := inserted_count + 1;
    END LOOP;
    RETURN inserted_count;
END;
$$;


--
-- Name: audit_territory_assignment_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.audit_territory_assignment_changes() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  atype text;
BEGIN
  atype := CASE TG_TABLE_NAME
    WHEN 'user_pincode_assignments' THEN 'PINCODE'
    WHEN 'user_area_assignments'    THEN 'AREA'
    WHEN 'user_client_assignments'  THEN 'CLIENT'
    WHEN 'user_product_assignments' THEN 'PRODUCT'
    ELSE TG_TABLE_NAME
  END;

  IF TG_OP = 'INSERT' THEN
    INSERT INTO territory_assignment_audit (
      user_id, assignment_type, assignment_id, action,
      previous_data, new_data, performed_by
    ) VALUES (
      NEW.user_id, atype, NEW.id, 'ASSIGNED', NULL,
      jsonb_build_object('assigned_by', NEW.assigned_by, 'is_active', NEW.is_active),
      COALESCE(NEW.assigned_by, NEW.user_id)
    );
  ELSIF TG_OP = 'UPDATE' THEN
    -- 2026-04-28 PE6: was 'UPDATED' but CHECK only allows MODIFIED.
    -- This silently broke every UPDATE on user_area/pincode_assignments.
    INSERT INTO territory_assignment_audit (
      user_id, assignment_type, assignment_id, action,
      previous_data, new_data, performed_by
    ) VALUES (
      NEW.user_id, atype, NEW.id, 'MODIFIED',
      jsonb_build_object('is_active', OLD.is_active),
      jsonb_build_object('is_active', NEW.is_active, 'assigned_by', NEW.assigned_by),
      COALESCE(NEW.assigned_by, NEW.user_id)
    );
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: compute_fiscal_year(timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.compute_fiscal_year(d timestamp with time zone DEFAULT now()) RETURNS character
    LANGUAGE sql IMMUTABLE
    AS $$
  SELECT CASE
    WHEN extract(month from d) >= 4
      THEN to_char(d, 'YYYY') || '-' || to_char(d + interval '1 year', 'YY')
    ELSE to_char(d - interval '1 year', 'YYYY') || '-' || to_char(d, 'YY')
  END::char(7);
$$;


--
-- Name: create_default_notification_preferences(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_default_notification_preferences() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  INSERT INTO notification_preferences (user_id)
  VALUES (NEW.id)
  ON CONFLICT (user_id) DO NOTHING;
  RETURN NEW;
END;
$$;


--
-- Name: create_rate_history(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_rate_history() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF TG_OP = 'UPDATE' AND OLD.amount != NEW.amount THEN
        INSERT INTO rate_history (rate_id, old_amount, new_amount, changed_by)
        VALUES (NEW.id, OLD.amount, NEW.amount, NEW.created_by);
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: enforce_verification_task_status_transition(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enforce_verification_task_status_transition() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  allowed BOOLEAN;
BEGIN
  -- No-op when status is unchanged. Still runs on UPDATEs that touch
  -- only other columns, which is fine — the early return keeps it
  -- cheap.
  IF NEW.status IS NOT DISTINCT FROM OLD.status THEN
    RETURN NEW;
  END IF;

  -- Allow NULL → any (covers the first INSERT path; technically this
  -- is a BEFORE UPDATE trigger so NULL OLD.status shouldn't happen,
  -- but be explicit).
  IF OLD.status IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT TRUE INTO allowed
  FROM task_status_transitions
  WHERE from_status = OLD.status
    AND to_status   = NEW.status
  LIMIT 1;

  IF allowed IS NULL THEN
    RAISE EXCEPTION 'Invalid verification_task status transition: % -> % (task id %)',
      OLD.status, NEW.status, OLD.id
      USING ERRCODE = '23514';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: ensure_audit_logs_partitions(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ensure_audit_logs_partitions(months_ahead integer DEFAULT 12) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    d date := date_trunc('month', CURRENT_DATE)::date;
    end_d date := date_trunc('month', CURRENT_DATE + (months_ahead || ' months')::interval)::date;
    pname text;
    created integer := 0;
BEGIN
    WHILE d <= end_d LOOP
        pname := 'audit_logs_' || to_char(d, 'YYYY_MM');
        IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = pname) THEN
            EXECUTE format(
                'CREATE TABLE %I PARTITION OF audit_logs FOR VALUES FROM (%L) TO (%L)',
                pname, d, (d + INTERVAL '1 month')::date
            );
            created := created + 1;
        END IF;
        d := (d + INTERVAL '1 month')::date;
    END LOOP;
    RETURN created;
END $$;


--
-- Name: ensure_notifications_partitions(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ensure_notifications_partitions(months_ahead integer DEFAULT 6) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  m int;
  start_date date;
  end_date date;
  partition_name text;
  created_count int := 0;
BEGIN
  FOR m IN 0..months_ahead LOOP
    start_date := date_trunc('month', current_date + make_interval(months => m))::date;
    end_date   := (start_date + interval '1 month')::date;
    partition_name := 'notifications_' || to_char(start_date, 'YYYY_MM');
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = partition_name) THEN
      EXECUTE format(
        'CREATE TABLE %I PARTITION OF notifications FOR VALUES FROM (%L) TO (%L)',
        partition_name, start_date, end_date
      );
      created_count := created_count + 1;
    END IF;

    partition_name := 'notification_delivery_log_' || to_char(start_date, 'YYYY_MM');
    IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = partition_name) THEN
      EXECUTE format(
        'CREATE TABLE %I PARTITION OF notification_delivery_log FOR VALUES FROM (%L) TO (%L)',
        partition_name, start_date, end_date
      );
      created_count := created_count + 1;
    END IF;
  END LOOP;
  RETURN created_count;
END;
$$;


--
-- Name: ensure_performance_metrics_partitions(integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.ensure_performance_metrics_partitions(days_ahead integer DEFAULT 30) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    d date := CURRENT_DATE;
    end_d date := CURRENT_DATE + (days_ahead || ' days')::interval;
    pname text;
    created integer := 0;
BEGIN
    WHILE d <= end_d LOOP
        pname := 'performance_metrics_' || to_char(d, 'YYYY_MM_DD');
        IF NOT EXISTS (SELECT 1 FROM pg_class WHERE relname = pname) THEN
            EXECUTE format(
                'CREATE TABLE %I PARTITION OF performance_metrics FOR VALUES FROM (%L) TO (%L)',
                pname, d, d + INTERVAL '1 day'
            );
            created := created + 1;
        END IF;
        d := d + INTERVAL '1 day';
    END LOOP;
    RETURN created;
END $$;


