--
-- Name: next_invoice_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.next_invoice_number() RETURNS TABLE(out_fiscal_year character, out_sequence_no integer, out_formatted_number character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_fy char(7) := compute_fiscal_year();
  v_fy_compact char(4);
  v_seq bigint;
BEGIN
  INSERT INTO invoice_sequences (fiscal_year, current_value)
    VALUES (v_fy, 1)
    ON CONFLICT (fiscal_year)
    DO UPDATE SET current_value = invoice_sequences.current_value + 1, updated_at = now()
  RETURNING current_value INTO v_seq;

  IF v_seq > 9999999 THEN
    RAISE EXCEPTION 'Invoice sequence exhausted for FY %; need multi-series prefix (e.g. INV2/...).', v_fy;
  END IF;

  v_fy_compact := substring(v_fy, 3, 2) || substring(v_fy, 6, 2);

  RETURN QUERY SELECT
    v_fy,
    v_seq::integer,
    ('INV/' || v_fy_compact || '/' || lpad(v_seq::text, 7, '0'))::varchar(16);
END $$;


--
-- Name: purge_expired_idempotency_keys(interval); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.purge_expired_idempotency_keys(grace interval DEFAULT '7 days'::interval) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
  deleted_count integer;
BEGIN
  DELETE FROM mobile_idempotency_keys WHERE expires_at < now() - grace;
  GET DIAGNOSTICS deleted_count = ROW_COUNT;
  RETURN deleted_count;
END;
$$;


