    LANGUAGE plpgsql
    AS $$
DECLARE deleted_count integer;
BEGIN
    DELETE FROM performance_metrics WHERE "timestamp" < now() - retention;
    GET DIAGNOSTICS deleted_count = ROW_COUNT;
    RETURN deleted_count;
END $$;


