--
-- Name: trg_invoices_immutability(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.trg_invoices_immutability() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.status IN ('ISSUED','SENT','PAID') AND OLD.is_locked = false THEN
    NEW.is_locked := true;
  END IF;
  IF OLD.is_locked = true AND NEW.is_locked = true THEN
    IF NEW.amount             IS DISTINCT FROM OLD.amount             OR
       NEW.subtotal_amount    IS DISTINCT FROM OLD.subtotal_amount    OR
       NEW.tax_amount         IS DISTINCT FROM OLD.tax_amount         OR
       NEW.total_amount       IS DISTINCT FROM OLD.total_amount       OR
       NEW.cgst_amount        IS DISTINCT FROM OLD.cgst_amount        OR
       NEW.sgst_amount        IS DISTINCT FROM OLD.sgst_amount        OR
       NEW.igst_amount        IS DISTINCT FROM OLD.igst_amount        OR
       NEW.cgst_rate          IS DISTINCT FROM OLD.cgst_rate          OR
       NEW.sgst_rate          IS DISTINCT FROM OLD.sgst_rate          OR
       NEW.igst_rate          IS DISTINCT FROM OLD.igst_rate          OR
       NEW.supply_type        IS DISTINCT FROM OLD.supply_type        OR
       NEW.place_of_supply    IS DISTINCT FROM OLD.place_of_supply    OR
       NEW.invoice_number     IS DISTINCT FROM OLD.invoice_number     OR
       NEW.client_id          IS DISTINCT FROM OLD.client_id          OR
       NEW.client_name        IS DISTINCT FROM OLD.client_name        OR
       NEW.issue_date         IS DISTINCT FROM OLD.issue_date         OR
       NEW.billing_period_from IS DISTINCT FROM OLD.billing_period_from OR
       NEW.billing_period_to  IS DISTINCT FROM OLD.billing_period_to
    THEN
      RAISE EXCEPTION 'F9.2.3: invoice % is locked; financial fields immutable. Issue a credit note instead.', OLD.invoice_number
        USING ERRCODE = 'restrict_violation';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


