--
-- Name: update_case_completion(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_case_completion() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    total_count INTEGER;
    completed_count INTEGER;
    forms_required_count INTEGER;
BEGIN
    SELECT
        COUNT(*),
        COUNT(*) FILTER (WHERE status = 'COMPLETED'),
        -- forms_required excludes KYC: only NORMAL + REVISIT tasks produce forms
        COUNT(*) FILTER (WHERE task_type IN ('NORMAL','REVISIT'))
    INTO total_count, completed_count, forms_required_count
    FROM verification_tasks WHERE case_id = NEW.case_id;

    IF total_count > 0 THEN
        UPDATE cases SET
            case_completion_percentage = ROUND((completed_count::numeric / total_count) * 100, 2),
            completed_tasks_count = completed_count,
            total_tasks_count = total_count,
            total_forms_required = forms_required_count,
            has_multiple_tasks = (total_count > 1),
            updated_at = NOW()
        WHERE id = NEW.case_id;
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: update_case_completion_percentage(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_case_completion_percentage() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    total_count INTEGER;
    completed_count INTEGER;
BEGIN
    SELECT COUNT(*), COUNT(*) FILTER (WHERE status = 'COMPLETED')
    INTO total_count, completed_count
    FROM verification_tasks WHERE case_id = NEW.case_id;

    IF total_count > 0 THEN
        UPDATE cases SET
            case_completion_percentage = ROUND((completed_count::numeric / total_count) * 100, 2),
            completed_tasks_count = completed_count,
            total_tasks_count = total_count,
            has_multiple_tasks = (total_count > 1),
            updated_at = NOW()
        WHERE id = NEW.case_id;
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: update_case_form_aggregates(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_case_form_aggregates() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    target_case_id uuid;
    submitted_count INTEGER;
    invalid_count INTEGER;
    required_count INTEGER;
BEGIN
    -- Pick the affected case_id from NEW (insert/update) or OLD (delete)
    target_case_id := COALESCE(NEW.case_id, OLD.case_id);
    IF target_case_id IS NULL THEN
        RETURN COALESCE(NEW, OLD);
    END IF;

    SELECT
        COUNT(*),
        COUNT(*) FILTER (WHERE validation_status IN ('INVALID','REQUIRES_REVIEW'))
    INTO submitted_count, invalid_count
    FROM form_submissions
    WHERE case_id = target_case_id;

    -- Use the case row's existing total_forms_required if set; else fall back
    -- to verification_tasks count to avoid a percentage of 0/0.
    SELECT COALESCE(total_forms_required, (SELECT COUNT(*) FROM verification_tasks WHERE case_id = target_case_id))
    INTO required_count
    FROM cases WHERE id = target_case_id;

    UPDATE cases SET
        forms_submitted_count = submitted_count,
        validation_issues_count = invalid_count,
        form_completion_percentage = CASE
            WHEN required_count > 0
                THEN ROUND((submitted_count::numeric / required_count) * 100, 2)
            ELSE 0
        END,
        updated_at = NOW()
    WHERE id = target_case_id;

    RETURN COALESCE(NEW, OLD);
END;
$$;


