--
-- Name: update_verification_report_attachment_counts(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_verification_report_attachment_counts() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  vt_id uuid;
BEGIN
  vt_id := COALESCE(NEW.verification_task_id, OLD.verification_task_id);
  IF vt_id IS NULL THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  UPDATE verification_reports
     SET total_images = COALESCE((
           SELECT COUNT(*)::int FROM verification_attachments
            WHERE verification_task_id = vt_id
              AND (photo_type IS NULL OR photo_type = 'verification')
              AND deleted_at IS NULL
         ), 0),
         total_selfies = COALESCE((
           SELECT COUNT(*)::int FROM verification_attachments
            WHERE verification_task_id = vt_id
              AND photo_type = 'selfie'
              AND deleted_at IS NULL
         ), 0)
   WHERE verification_task_id = vt_id;
  RETURN COALESCE(NEW, OLD);
END $$;


