--
-- Name: validate_custom_fields_shape(jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_custom_fields_shape(cf jsonb) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
  elem jsonb;
BEGIN
  IF cf IS NULL THEN
    RETURN true;
  END IF;
  IF jsonb_typeof(cf) <> 'array' THEN
    RETURN false;
  END IF;
  FOR elem IN SELECT * FROM jsonb_array_elements(cf) LOOP
    IF jsonb_typeof(elem) <> 'object'
       OR NOT (elem ? 'key')
       OR NOT (elem ? 'type')
       OR NOT (elem ? 'label')
       OR NOT (elem ? 'required')
       OR jsonb_typeof(elem->'key') <> 'string'
       OR length(elem->>'key') = 0
       OR jsonb_typeof(elem->'label') <> 'string'
       OR length(elem->>'label') = 0
       OR jsonb_typeof(elem->'required') <> 'boolean'
       OR (elem->>'type') NOT IN ('text', 'date', 'number', 'select', 'checkbox')
    THEN
      RETURN false;
    END IF;
  END LOOP;
  RETURN true;
END;
$$;


--
-- Name: validate_device_id(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.validate_device_id() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
BEGIN
    IF NEW.device_id IS NOT NULL AND NEW.device_id !~ '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' THEN
        RAISE EXCEPTION 'device_id must be a valid UUID format';
    END IF;
    RETURN NEW;
END;
$_$;


--
-- Name: verification_attachments_freeze_address(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.verification_attachments_freeze_address() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Allow exactly one transition: NULL -> address. Any further change
  -- (address -> different address, address -> NULL) is blocked at the
  -- DB level so verification evidence cannot be re-written silently.
  IF OLD.reverse_geocoded_address IS NOT NULL
     AND NEW.reverse_geocoded_address IS DISTINCT FROM OLD.reverse_geocoded_address
  THEN
    RAISE EXCEPTION
      'verification_attachments.reverse_geocoded_address is immutable once set (attachment id=%)',
      OLD.id
      USING HINT = 'The reverse-geocoded address is frozen for evidence integrity. Create a separate audited override column if correction is genuinely needed.';
  END IF;
  RETURN NEW;
END;
$$;


