    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    id integer NOT NULL,
    logo_url character varying(500),
    stamp_url character varying(500),
    primary_color character varying(20),
    header_color character varying(20),
    deleted_at timestamp with time zone,
    gstin character(15),
    pan character(10),
    gstin_state_code character(2),
    billing_address_line1 character varying(255),
    billing_address_line2 character varying(255),
