    billing_state_id integer,
    billing_pincode character varying(10),
    tier character varying(20),
    billing_country_id integer,
    CONSTRAINT chk_clients_tier CHECK (((tier IS NULL) OR ((tier)::text = ANY ((ARRAY['STARTER'::character varying, 'GROWTH'::character varying, 'ENTERPRISE'::character varying])::text[])))),
    CONSTRAINT clients_billing_pincode_format CHECK (((billing_pincode IS NULL) OR ((billing_pincode)::text ~ '^[1-9][0-9]{5}$'::text))),
    CONSTRAINT clients_gstin_format CHECK (((gstin IS NULL) OR (gstin ~ '^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z][0-9][A-Z][0-9A-Z]$'::text))),
    CONSTRAINT clients_gstin_state_code_format CHECK (((gstin_state_code IS NULL) OR (gstin_state_code ~ '^[0-9]{2}$'::text))),
    CONSTRAINT clients_gstin_state_code_match CHECK (((gstin IS NULL) OR (gstin_state_code IS NULL) OR (SUBSTRING(gstin FROM 1 FOR 2) = (gstin_state_code)::text))),
    CONSTRAINT clients_pan_format CHECK (((pan IS NULL) OR (pan ~ '^[A-Z]{5}[0-9]{4}[A-Z]$'::text)))
);


