--

COMMENT ON CONSTRAINT chk_vt_type_matches_task_type ON public.verification_tasks IS 'KYC carve-out for F5.2.2: field-verification tasks (NORMAL/REVISIT) require verification_type_id (FK to verification_types — 9 field types). KYC tasks have NULL verification_type_id; their document_type lives on kyc_document_verifications.document_type_id (FK to document_types).';


--
-- Name: case_completion_analytics; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.case_completion_analytics AS
 SELECT c.id,
    c.case_id,
    c.customer_name,
    c.status,
    c.priority,
    c.client_id,
    cl.name AS client_name,
    vt.assigned_to,
    u.name AS agent_name,
    u.employee_id,
    c.form_completion_percentage,
    NULL::numeric(5,2) AS quality_score,
    c.forms_submitted_count,
    c.total_forms_required,
    c.forms_submitted_count AS actual_forms_submitted,
    GREATEST((c.forms_submitted_count - c.validation_issues_count), 0) AS valid_forms,
    COALESCE(( SELECT (count(*))::integer AS count
           FROM public.attachments a
          WHERE (a.case_id = c.id)), 0) AS attachment_count,
        CASE
            WHEN (c.completed_at IS NOT NULL) THEN (EXTRACT(epoch FROM (c.completed_at - c.created_at)) / (86400)::numeric)
            ELSE NULL::numeric
        END AS completion_days,
    c.created_at,
    c.updated_at
   FROM (((public.cases c
     LEFT JOIN public.clients cl ON ((cl.id = c.client_id)))
     LEFT JOIN LATERAL ( SELECT vt2.assigned_to
           FROM public.verification_tasks vt2
          WHERE ((vt2.case_id = c.id) AND (vt2.assigned_to IS NOT NULL))
          ORDER BY vt2.assigned_at DESC NULLS LAST
         LIMIT 1) vt ON (true))
     LEFT JOIN public.users u ON ((u.id = vt.assigned_to)));


