--
-- Name: field_agent_territories; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.field_agent_territories AS
 SELECT u.id AS user_id,
    u.name AS user_name,
    u.username,
    u.employee_id,
    upa.id AS pincode_assignment_id,
    p.id AS pincode_id,
    p.code AS pincode_code,
    c.name AS city_name,
    s.name AS state_name,
    co.name AS country_name,
    COALESCE(json_agg(json_build_object('areaAssignmentId', uaa.id, 'areaId', a.id, 'areaName', a.name, 'assignedAt', uaa.assigned_at) ORDER BY a.name) FILTER (WHERE (a.id IS NOT NULL)), '[]'::json) AS assigned_areas,
    upa.assigned_at AS pincode_assigned_at,
    upa.assigned_by,
    upa.is_active
   FROM (((((((public.users u
     JOIN public.user_pincode_assignments upa ON ((u.id = upa.user_id)))
     JOIN public.pincodes p ON ((upa.pincode_id = p.id)))
     JOIN public.cities c ON ((p.city_id = c.id)))
     JOIN public.states s ON ((c.state_id = s.id)))
     JOIN public.countries co ON ((s.country_id = co.id)))
     LEFT JOIN public.user_area_assignments uaa ON (((upa.id = uaa.user_pincode_assignment_id) AND (uaa.is_active = true))))
     LEFT JOIN public.areas a ON ((uaa.area_id = a.id)))
  WHERE (upa.is_active = true)
  GROUP BY u.id, u.name, u.username, u.employee_id, upa.id, p.id, p.code, c.name, s.name, co.name, upa.assigned_at, upa.assigned_by, upa.is_active;


