    CONSTRAINT chk_invoices_gst_consistency CHECK (((supply_type IS NULL) OR (((supply_type)::text = 'INTRA_STATE'::text) AND (cgst_amount IS NOT NULL) AND (sgst_amount IS NOT NULL) AND (igst_amount IS NULL)) OR (((supply_type)::text = 'INTER_STATE'::text) AND (igst_amount IS NOT NULL) AND (cgst_amount IS NULL) AND (sgst_amount IS NULL)) OR (((supply_type)::text = 'EXPORT'::text) AND (cgst_amount IS NULL) AND (sgst_amount IS NULL) AND (igst_amount IS NULL)))),
    CONSTRAINT chk_invoices_supply_type CHECK (((supply_type IS NULL) OR ((supply_type)::text = ANY ((ARRAY['INTRA_STATE'::character varying, 'INTER_STATE'::character varying, 'EXPORT'::character varying])::text[]))))
);


