    push_token text NOT NULL,
    is_active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now(),
    last_used_at timestamp with time zone DEFAULT now(),
    CONSTRAINT chk_notification_tokens_platform CHECK (((platform)::text = ANY ((ARRAY['IOS'::character varying, 'ANDROID'::character varying, 'WEB'::character varying])::text[])))
);


--
-- Name: CONSTRAINT chk_notification_tokens_platform ON notification_tokens; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON CONSTRAINT chk_notification_tokens_platform ON public.notification_tokens IS 'F10.2.1: UPPERCASE-only per project_uppercase_enforcement.md. Was previously dual-case which baked drift into the constraint.';


