--

CREATE TABLE public.user_product_assignments (
    id integer NOT NULL,
    user_id uuid NOT NULL,
    product_id integer NOT NULL,
    assigned_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    assigned_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT CURRENT_TIMESTAMP,
    is_active boolean DEFAULT true NOT NULL,
    valid_from timestamp with time zone DEFAULT now() NOT NULL,
    valid_until timestamp with time zone,
    revoked_at timestamp with time zone,
    revoked_reason text
);


--
-- Name: TABLE user_product_assignments; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.user_product_assignments IS 'Junction table for assigning BACKEND users to specific products for access control';


--
-- Name: COLUMN user_product_assignments.user_id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.user_product_assignments.user_id IS 'Reference to the user being assigned to products';


--
-- Name: COLUMN user_product_assignments.product_id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.user_product_assignments.product_id IS 'Reference to the product the user has access to';


--
-- Name: COLUMN user_product_assignments.assigned_at; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.user_product_assignments.assigned_at IS 'Timestamp when the assignment was made';


--
-- Name: COLUMN user_product_assignments.assigned_by; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.user_product_assignments.assigned_by IS 'User who made the assignment';


--
