--

ALTER TABLE ONLY public.rates
    ADD CONSTRAINT rates_no_overlap EXCLUDE USING gist (client_id WITH =, product_id WITH =, COALESCE(verification_type_id, '-1'::integer) WITH =, COALESCE(rate_type_id, '-1'::integer) WITH =, tstzrange(effective_from, COALESCE(effective_to, 'infinity'::timestamp with time zone), '[)'::text) WITH &&) WHERE ((is_active = true));


--
-- Name: CONSTRAINT rates_no_overlap ON rates; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON CONSTRAINT rates_no_overlap ON public.rates IS 'F9.1.1: prevents two active rates with overlapping date ranges for the same scope';


